var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"흐엑. 줄이 너무 길잖아!","JPN":"うげっ。行列長すぎ！","ENG":"Whoa...! This is the line?!","TWN":"哇賽，隊伍會不會太長？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"그야 옆 마을까지 소문이 쫙 퍼졌으니까 그렇지. 이 정도면 적은 편일 걸?","JPN":"そりゃあ、隣街まで噂になってるからだろ。この程度なら少ない方かもな。","ENG":"That's because word got out to the next town over. Given that, this isn't that long.","TWN":"因為已經紅到隔壁村啦，今天這樣還算人少的吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"아무래도 못 미더웠는데…… 솔직히 악몽을 꾸지 않게 해주는 거 치고 엄청 싸잖아?","JPN":"どうも信じられなかったんだけど……正直、悪夢を見ないようにしてくれるって言う割には安すぎないか？","ENG":"I still can’t believe it... They get rid of your nightmares for chump change?","TWN":"真是誇張……不過以能讓你不再做惡夢來說，收費會不會太便宜？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"아직도 그 소리야? 이미 다녀간 사람들의 수많은 후기가 증명한다니까.","JPN":"まだそんなこと言ってるのか？　経験者たちの膨大なレビューが証明してるだろ。","ENG":"Why are you still questioning that? Haven’t you seen the countless reviews proving this place is legit?","TWN":"你還在懷疑喔？已經有很多人去完都說有效欸！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"알았어. 근데 왠지…… 아까보다 달이 더 흐릿해진 것 같지 않아?","JPN":"わかったよ。それより、なんか……さっきより月がぼやけて見えないか？","ENG":"Fine. But hey... Don't you think the moon is a little blurrier than before?","TWN":"好吧，不過……不覺得月亮好像變得有點模糊嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GUEST_VOICE_NULL_NULL","text":{"KOREA":"감사합니다, 감사합니다!","JPN":"ありがとうございます、ありがとうございます！","ENG":"Thank you! Thank you so much!","TWN":"謝謝，謝謝！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네네~ 조심히 가시고 친구 분들께 저희 얘기하는 거 잊지 마세요?","JPN":"はいは～い、お気をつけて。お友達に私たちのことよろしく伝えてくださいね？","ENG":"You're welcome! Don’t forget to tell your friends and family about us!","TWN":"不會～回家小心，記得要幫我們多跟親友宣傳喔～"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GUEST_VOICE_NULL_NULL","text":{"KOREA":"당연하죠! 연락 다 돌릴 거예요.","JPN":"もちろんです！　みんなに連絡しますよ。","ENG":"I won’t! I’m going to call them right now!","TWN":"那當然！他們一定都會來找你的！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GUEST_VOICE_NULL_NULL","text":{"KOREA":"저…… 근데 혹시 카드도 받나요?","JPN":"あの……カードも使えますか？","ENG":"Um... Do you take credit cards too?","TWN":"請問……可以刷卡嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"혹시 돈이 없니? 그럼 오늘은 그냥…….","JPN":"もしかしてお金がないの？　それじゃあ、今日はただで……","ENG":"Do you not have money? Then I’ll─","TWN":"你沒錢嗎？那今天就……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아앗. 손님~ 그건 조금 힘드세요. 우리 루루 님께서 능력을 상업적으로 이용하는 건 싫으시대서 조금의 수고비만 받는 거라고 그렇게 말씀드렸는데~","JPN":"ああっ。お客様～それは困ります。ルル様は能力を商業的に利用するのがお嫌いなので、ほんの少しの手数料だけをいただきますとあれほどご案内しましたのに～","ENG":"Sorry, but that won't work for us. Miss Lulu here stated that she does not wish to use her abilities commercially, which is why we are only charging a small commission fee.","TWN":"哎呀～這位客人，這樣有點為難呢。一開始就有說，我們露露老師不願意利用她的能力來賺錢，所以只會收一些車馬費～"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GUEST_VOICE_NULL_NULL","text":{"KOREA":"죄, 죄송합니다! 여기 크레딧 있어요!","JPN":"す、すみません！　これ、現金です！","ENG":"I-I didn’t know. I’m sorry! Here’re your credits!","TWN":"對…對不起！我這裡有金幣！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"감사합니다, 손님! 밤길도 어두운데 살펴 가세요~","JPN":"ありがとうございます、お客様！　夜道、気をつけてお帰りくださ～い。","ENG":"Thank you! Get home safe!","TWN":"謝謝光臨！天那麼黑，小心別跌倒喔～"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"흐으……","JPN":"ふう……","ENG":"Hngh...","TWN":"呵……"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다? 울어? 혹시 내가 돈을 안 받으려고 해서 그런 거면…….","JPN":"グリンダ？　泣いてるの？　もしかして私がお金を受け取ろうとしないから……","ENG":"Glinda? Are you crying? Is it because I said I didn’t want any money?","TWN":"格琳達？你在哭嗎？是因為我本來想說不收錢嗎……"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"흐으…… 흐흐흐. 우린 이제 떼부자야!","JPN":"ふ……ふふふ。私たち、もうお金持ちなんだよ！","ENG":"Hngh... Hehehe...! We’re rich!","TWN":"呵呵……呵呵呵，我們現在是大富翁啦！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루! 이게 다 얼마야! 몇 달 하지도 않았는데 돈을 엄청 벌었잖아!","JPN":"ルル！　このお金見なよ！　何か月もしてないのに、こんなに儲けたんだよ！","ENG":"Lulu! Look at all the money! We’ve only been doing this for a couple of months and we’ve already made this much!","TWN":"露露！你看這裡有多少錢！我們才做幾個月而已，就賺到這麼多錢咧！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"……그게 그렇게 좋아?","JPN":"……それがそんなに嬉しいの？","ENG":"Does that make you happy?","TWN":"……這麼開心喔？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"당연하지! 왜, 너무 속물 같아?","JPN":"当たり前でしょ！　なに、俗物的すぎ？","ENG":"Of course! Why? Do I look money hungry?","TWN":"當然！幹嘛？覺得我很庸俗嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"아니. 솔직해서 보기 좋아.","JPN":"ううん。素直でいいと思う。","ENG":"No, it's nice to see you being honest.","TWN":"不是，我喜歡你的率真。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다는 정말 대단하네. 아무것도 없는데 돈도 벌잖아.","JPN":"グリンダは本当にすごいね。何もないところからお金も稼いで。","ENG":"Glinda, you’re amazing. You made money out of nothing.","TWN":"格琳達，你真的很厲害，一無所有也可以賺到錢。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아무것도 없기는. 네 능력이 있잖아. 이 시대에 아주 딱 맞는!","JPN":"何もないって。アンタの能力があるじゃん。この時代にピッタリの！","ENG":"It’s not nothing. We made use of your abilities! It just so happened that we were in the right place at the right time!","TWN":"什麼一無所有，不是有你的能力嗎？這個世代正需要的東西！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"난…… 내 능력으로 돈 벌 생각은 못 해봤어.","JPN":"私は……自分の能力でお金を稼ぐなんて思ってもみなかったよ。","ENG":"I... never thought about making money using my abilities.","TWN":"我……從沒想過要靠我的能力賺錢。"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"돈도 벌면서 사람들 악몽까지 없애 줄 수 있다니…… 어떻게 이런 생각을 했어, 글린다?","JPN":"お金を稼ぎながら、人の悪夢まで消してあげられるなんて……どうやってこんなこと思いついたの？","ENG":"Making money while getting rid of their nightmares... How did you come up with this, Glinda?","TWN":"既可以賺錢，又可以幫助人不再做惡夢……你是怎麼想到這麼棒的方法的，格琳達？"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"훗. 나처럼 산전수전 노숙전 다 거치고 궁핍해져 봐야 이런 사업 수완이 생기는 거야.","JPN":"ふっ。私みたいに海千山千、野宿千までして貧乏になってみるとこんな商売が思いつくんだよ。","ENG":"Heh. If you go through enough hardships like me, you’ll also see hidden opportunities everywhere.","TWN":"哈，只要你跟我一樣，一直過著顛沛流離、有一餐沒一餐的生活，自然會有跟我一樣的生意頭腦囉～"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L36_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"용케도 지금까지 살아 남았다, 너. 이제부턴 내가 있으니까 걱정 붙들어 매.","JPN":"アンタ、よく今まで生き延びたね。これからは私がいるから心配ご無用。","ENG":"It’s a miracle you're still alive. And don’t you worry, since I’m right here beside you.","TWN":"我好不容易才活到現在，現在起有我在，你就放一百萬個心吧！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L37_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응!","JPN":"うん！","ENG":"Okay!","TWN":"嗯！"},"stage":{"bg":"DORMITORY_2","bgm":"THEMA_CHILD","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L39_1","type":"dialog","speaker":"SIGMA_RAS_DREAM_NULL","text":{"KOREA":"호오. 이 맑은 공기는…… 정령님의 가호가 넘치는 곳이로군요.","JPN":"ほう。この澄んだ空気……精霊様の加護が溢れている場所ですね。","ENG":"Ooh... The air is so fresh... This place must be overflowing with the spirit’s blessing.","TWN":"喔呵，空氣好清新……看來這裡是受到精靈大人看顧的地方。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SIGMA_RAS_DREAM_NULL","text":{"KOREA":"소문이 사실인가 보네요.","JPN":"噂は本当のようです。","ENG":"I see that the rumors are true.","TWN":"傳言是真的？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네? 손님, 다짜고짜 무슨 말씀을…….","JPN":"はい？　お客様、いきなり何を……","ENG":"Huh? Miss? I don’t understand what you’re talking about...","TWN":"什麼？這位客人你在自言自語……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SIGMA_RAS_DREAM_NULL","text":{"KOREA":"아. 실례했군요.","JPN":"あ。これは失礼。","ENG":"Oh, excuse me.","TWN":"哎呀，真是不好意思。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"저는 <color=#ffd34c>별의 인도자 마담 스타시커</color>. 정령님의 가호를 받아 사람들에게 좋은 말씀을 전하고 있습니다.","JPN":"私は<color=#ffd34c>星の導く者、マダムスターシーカー</color>。精霊様の加護を受け、人々にありがたい御言葉をお伝えしております。","ENG":"I am <color=#ffd34c>Star Guide Madam Starseeker</color>. I’m here to deliver good words to people with the blessing of the spirit.","TWN":"我是<color=#ffd34c>星星的引導者 尋星夫人</color>，專門向人們報好消息的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"물론 불길한 기운을 물리쳐 주는 부적도 매우 싼 가격에 제공하고 있답니다. 훗.","JPN":"もちろん不吉な気を追い払ってくれるお守りも激安で提供していますよ。ふっ。","ENG":"Also, we provide these charms that expel evil energy at affordable prices. Heh.","TWN":"另外也有提供趨吉避凶的護身符，很便宜喔，呵。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"마담 스타시커? 이 바닥에서 엄청 유명한 사람이잖아?!","JPN":"マダムスターシーカー？　この業界でめっちゃ有名な人じゃん！？","ENG":"Madam Starseeker? You’re that famous person in this industry!","TWN":"尋星夫人？超有名的欸！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"여긴 어쩐 일이시죠? 혹시 악몽을 없애러 오셨나요?","JPN":"ここにはどんなご用で？　もしかして悪夢を消すために？","ENG":"What brings you here? Are you here to get your nightmare removed?","TWN":"怎麼會大駕光臨呢？您也是來消除惡夢的嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"악몽은 괜찮습니다. 그저 동종 업계에서 떠도는 소문을 직접 확인하고 싶었을 뿐이니까요.","JPN":"悪夢はいいのです。ただ、同じ業界に流れている噂を直接確認してみたかっただけですから。","ENG":"No nightmare removals tonight. I just came by to see what all the rumors were floating about this place.","TWN":"惡夢我個人是還好，只是最近在業界有些傳聞，我是來確認的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"소문이라면…….","JPN":"噂といいますと……","ENG":"What you mean by rumors is...","TWN":"傳聞……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"몇 달 전 혜성처럼 나타나서 터무니없이 싼 가격에 사람들의 악몽을 없애 주는 술사가 나타났다더군요.","JPN":"何ヶ月か前に彗星のように現れ、とてつもなく安い値段で人々の悪夢を消してくれる術者が現れたというのです。","ENG":"Rumors about a sorcerer who appeared out of nowhere a few months ago, removing nightmares for a ridiculously low price.","TWN":"我聽說在幾個月前，突然有位老師像彗星般降臨，以誇張的便宜價格替人消除惡夢。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"또 어떤 불경한 자가 사람들에게 헛된 희망을 심나 걱정이 되어 달려왔는데……","JPN":"どんな不信仰者が人々に虚しい希望を与えているのか、心配になって駆けつけてみたのですが……","ENG":"I was worried some hack was scamming people out of their money with false hopes, but...","TWN":"我擔心又是哪個江湖術士在招搖撞騙，就跑來看看……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"와서 보니 공기도 맑고 훈훈한 게 진실된 자임이 틀림없어요.","JPN":"来てみれば空気も澄んでいて温かく、真なる者に違いありません。","ENG":"Seeing this place for myself and the aura surrounding it, I have no doubt you are the real deal.","TWN":"一看發現，空氣很清新又很溫暖，應該不是騙人的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그건 공기청정기랑 난방을 틀어서 그런 거긴 한데…… 아무튼 좋게 봐 줘서 고마워요.","JPN":"それは空気清浄機と暖房のおかげだと思いますが……とにかく好意的に見てくれてありがとうございます。","ENG":"Well, that’s just because we have the heat up as well as the air purifier... But thank you, I guess?","TWN":"應該是因為我們有開空氣清淨機跟暖氣吧……不過還是謝謝你的好評。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"하지만, 이곳에 딱 하나 부족한 게 있습니다.","JPN":"ですが、ここにたった一つ、足りないものがあります。","ENG":"However, this place is missing just one thing.","TWN":"不過，這裡還缺一樣東西。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그, 그게 뭐죠?","JPN":"な、なんですか？","ENG":"W-what might that be?","TWN":"缺…缺什麼？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"바로 불안에 떨고 있는 손님에게 제공할 부적이죠!","JPN":"不安に震えているお客さんに提供するお守りです！","ENG":"A charm to offer to your worried customers!","TWN":"就是針對心靈不安的客人，可以提供給他們的護身符！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"마침 제게 불안을 없애 주는 부적이 왕창 있으니 원하신다면 떨이 가격으로 제공해드리도록 하겠습니다.","JPN":"ちょうど不安を消すお守りをたくさん持っておりますので、お望みであれば激安で提供してさしあげましょう。","ENG":"It just so happens that I brought a ton of charms that relieve anxiety. If you want, I can give them to you at a discounted rate.","TWN":"正好我有帶很多可以消滅不安的護身符，需要的話我可以用破盤價賣你們。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"무려 65% 할인에 효과 확실한 부적을 다량으로! 아, 싸다 싸~","JPN":"なんと65％割引で、効果抜群のお守りを多量に！　ああ、安い安い～","ENG":"Buy your tried-and-true charms in bulk and save 65%! I’m practically giving it to you for free!","TWN":"可以用3.5折的價格買到大量有效的護身符喔！太划算啦～"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"클로에! 금방 나온다면서! 파르페 먹으러 안 갈 거야?","JPN":"クロエ！　すぐ出るって言ったじゃない！　パフェ食べに行かないの？","ENG":"Chloe! You said you’d only take a second! Aren’t you gonna go eat a parfait?","TWN":"克洛伊！你不是說出來一下而已嗎？要不要去吃聖代啦？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"지, 지금 가……!","JPN":"い、今行く……！","ENG":"I-I’m coming...!","TWN":"要…我要去……！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L11_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_MADAM","text":{"KOREA":"크흠. 아무튼 생각 있으시면 마담 스타시커의 블로그로 연락 주시죠. 그럼 이만.","JPN":"コホン。とにかく、よかったらマダムスターシーカーのブログにご連絡ください。それじゃあ。","ENG":"Ahem! Anyway, if you’re interested, please contact me through Madam Seeker blog. Now, excuse me.","TWN":"咳咳，你們有興趣的話再跟我的粉專聯絡吧，再會。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHLOE_COFFIN_NULL_MADAM","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHLOE_COFFIN_NULL_NULL","text":{"KOREA":"레나 양! 같이 가지 않으면 파르페 먹다가 얼음 덩어리가 씹히는 저주를 걸어 버릴 거예요!","JPN":"レナ！　一緒に行かないと、パフェ食べる時氷の塊を噛む呪いをかけちゃいますよ！","ENG":"Lena! I'm going to curse you so that you chomp ice while eating your parfait if you don't wait for me!","TWN":"蕾娜！等我！不然我會詛咒你吃聖代時吃到冰塊喔！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루.","JPN":"ルル。","ENG":"Lulu?","TWN":"露露。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응?","JPN":"うん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"앞으로 손님들하고 말하는 건 내가 다 할게.","JPN":"これからお客さんと話すのは全部私がやるよ。","ENG":"I’ll do all the talking to the customers from now on.","TWN":"之後就由我來和客人應對吧！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"왜……?","JPN":"どうして……？","ENG":"Why...?","TWN":"為什麼……？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"보니까 이쪽 계열은 좀 이상하게 보여야 사람들이 더 잘 믿는 것 같아.","JPN":"どうやら、こっち系はちょっと変に見える方がみんな信じやすいみたい。","ENG":"People seem to believe it more when the representative appears pretty weird.","TWN":"因為這樣看起來，我們要再怪一點，人們才會更相信。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L23_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"마담 스타시커도…… 상당히 이상해 보였지?","JPN":"マダムスターシーカーも……相当変だったじゃん？","ENG":"Didn’t Madam Seeker... also behave a little strange to you?","TWN":"尋星夫人……也很怪吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yes.","TWN":"嗯。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"좀 사이비 같은데, 그래서 그런 건지는 몰라도 생각보다 용하대.","JPN":"ちょっぴりインチキくさいけど、それも手伝ってか思ったよりよく当たるらしいよ。","ENG":"She appears to be a hoax, but perhaps that is why people say she is better than they expected.","TWN":"好像有點裝神弄鬼，或許就是因為這樣，才覺得很靈驗吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아 그래. 말을 할 거면 마담 스타시커처럼 말하는 것도 괜찮겠다.","JPN":"あ、そうだ。話す時にマダムスターシーカーみたいにするのもいいね。","ENG":"Oh! And might as well start talking like her too.","TWN":"對了，說話方式也學一下吧！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"<color=#ffd34c>정령님께서 속삭여 주셨습니다. 당신을 재워서 이 악몽을 가져가 주라고.</color> 따라해 볼래?","JPN":"<color=#ffd34c>精霊様がささやいてくださいました。貴方を寝かしてこの悪夢を取り込めと。</color>やってみて？","ENG":"Repeat after me, okay? <color=#ffd34c>The spirit has spoken... To take away your frightful nightmares.</color>","TWN":"<color=#ffd34c>精靈大人跟我說，讓你入睡將惡夢帶走。</color>你可以照著說一次嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"정령님……이 뭔데?","JPN":"精霊様……ってなに？","ENG":"What is... \\"the spirit\\"?","TWN":"精靈大人……是什麼？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그냥 웬만하면 내가 다 말할게. 넌 능력 발휘만 해라.","JPN":"なるべく私だけ話すよ。アンタは能力発揮に専念して。","ENG":"I’ll just do most of the talking. You focus on your abilities.","TWN":"說話的部分我會盡量Cover，你只需要發揮能力就好。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"진짜 정 말을 꺼내야겠으면 <color=#ffd34c>루</color>로만 말하던가 해. 알겠어?","JPN":"どうしても話したいなら、<color=#ffd34c>ル</color>だけで話すとかさ。わかった？","ENG":"If you really want to say something, just say <color=#ffd34c>lu</color>. Got that?","TWN":"萬一真的逼不得已需要開口，那你就說<color=#ffd34c>露</color>就好，知道嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"알았어.","JPN":"わかった。","ENG":"Got it.","TWN":"知道。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"<color=#ffd34c>루</color>로만 말하라니까?","JPN":"<color=#ffd34c>ル</color>だけで話せってば。","ENG":"Hey, I said to only say <color=#ffd34c>lu</color>.","TWN":"不是叫你說<color=#ffd34c>露</color>就好嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"알았어<color=#ffd34c>루</color>.","JPN":"わかった<color=#ffd34c>ル</color>。","ENG":"Got it-<color=#ffd34c>lu</color>.","TWN":"好，<color=#ffd34c>露</color>。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……그래. 그 정도면 충분히 이상해 보이네.","JPN":"……その調子。そんくらいだったら十分変に見えるね。","ENG":"...Yeah. Seems weird enough.","TWN":"……很好，這樣看起來應該夠怪吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이… 이상해 보인다는 게 네가 이상하다는 게 아니라 지금 충분히 잘하고 있다는 거야!","JPN":"へ……変ってのはアンタが変ってことじゃなくて、今十分よくやってるってことだよ！","ENG":"I-I’m not saying that you’re weird...! Just that you’re doing a good job!","TWN":"呃…不是說你看起來很怪，是指你做得很到味啦！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아, 아무튼 루루. 우리 같은 인연이 또 어디 있겠어?","JPN":"と、とにかくルル。私たちみたいな縁はどこにもないんだ。","ENG":"A-anyway, Lulu. We make a great team, no?","TWN":"那個，露露，我們的緣分也真很奇妙，你說是不是？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"인연?","JPN":"縁？","ENG":"Team?","TWN":"緣分？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"날 좀 봐! 위저드 찌끄레기 말단에서 돈 버는 사업가가 됐잖아!","JPN":"私を見なよ！　ウィザードのカスみたいな下っ端からお金を稼ぐ事業家になったじゃん！","ENG":"Look at me! I was a Wizard grunt, but now I’m a successful businesswoman!","TWN":"你看我！原本魔法師最底層的嘍囉，現在卻是生意人！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"너도 하려던 일 마저 하면서 돈도 벌 수 있고.","JPN":"アンタもやろうとしてた仕事しながらお金も稼げるしさ。","ENG":"Plus, you get to do what you need while making money on the side.","TWN":"你也是，不僅可以做你想做的事，還可以賺錢！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이런 게 바로 운명이지. 그, 정령님이라는 분이 나한테 널 인도해 주셨을 수도!","JPN":"これこそ運命だよ。その、精霊様って方が私にアンタを導いてくれたのかも！","ENG":"If that’s not fate, I don’t know what is! Maybe it was that spirit that guided me to you?","TWN":"這就是命運的相遇吧？可能是那個精靈大人藉由我引導你的！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"으응. 정령님은 모르겠지만…….","JPN":"うん。精霊様はよくわからないけど……","ENG":"Um... I don’t know about any spirit, but...","TWN":"嗯嗯，雖然我不認識精靈大人……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"이런 식으로 계속 같이 지내자. 넌 악몽을 없애고, 나는 돈을 벌고. 어때? 이 정도면 좋은 파트너 아냐?","JPN":"こんな風にずっと一緒にいよう。アンタは悪夢を消して、私をお金を稼いで。どう？　これならいいパートナーじゃない？","ENG":"Let's keep working together like this. I make money while you get rid of nightmares. So? Doesn’t that sound like the perfect partner?","TWN":"我們就繼續一起生活下去吧！你負責消除惡夢，我負責賺錢，怎麼樣？這樣應該算是好夥伴吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SIGMA_RAS_DREAM_NULL","text":{"KOREA":"아직 운영 중인가요?","JPN":"まだ大丈夫かしら？","ENG":"Are you still open?","TWN":"請問還收客人嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"네네~ 손님, 잠시만요!","JPN":"はいは～い。お客様、少々お待ちください！","ENG":"Yes! Just a minute, please!","TWN":"有的～稍等一下！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"손님 오셨나 보다.","JPN":"お客さんだ。","ENG":"Looks like we have another customer.","TWN":"好像有客人上門咧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루. 잘할 수 있지?","JPN":"ルル。ちゃんとできる？","ENG":"Lulu, you good?","TWN":"露露，你沒問題吧？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응! 잘할 수 있어<color=#ffd34c>루</color>!","JPN":"うん！　できる<color=#ffd34c>ル</color>！","ENG":"Yes! I’m good-<color=#ffd34c>lu</color>!","TWN":"嗯！我可以的，<color=#ffd34c>露</color>！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}},"sfx":"FX_CUTSCEN_BEEP2"},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"아주 좋아.","JPN":"上出来。","ENG":"Nice.","TWN":"非常好！"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"손님~ 문 열어드릴게요~","JPN":"お客様～扉お開けしますね～","ENG":"We’ll be with you in just a sec!","TWN":"你好～我來開門～"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"계속… 같이…….","JPN":"ずっと……一緒……","ENG":"Together... like this...","TWN":"繼續…一起……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"여기가…… 소문의 그곳. 맞나요?","JPN":"ここが……あの噂の、ですね？","ENG":"Is this... where the rumors are all about?","TWN":"這裡……是傳說中的那個地方嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};